        tile[533] += sc * (Gx[1]) * (Gy[1]) * (Gz[12] * zij2 + 2.0 * (Gz[17] * zij) + Gz[22]);
        tile[534] += sc * (Gx[1]) * (Gy[0]) * (Gz[13] * zij2 + 2.0 * (Gz[18] * zij) + Gz[23]);
        tile[535] += sc * (Gx[0]) * (Gy[4]) * (Gz[10] * zij2 + 2.0 * (Gz[15] * zij) + Gz[20]);
        tile[536] += sc * (Gx[0]) * (Gy[3]) * (Gz[11] * zij2 + 2.0 * (Gz[16] * zij) + Gz[21]);
        tile[537] += sc * (Gx[0]) * (Gy[2]) * (Gz[12] * zij2 + 2.0 * (Gz[17] * zij) + Gz[22]);
        tile[538] += sc * (Gx[0]) * (Gy[1]) * (Gz[13] * zij2 + 2.0 * (Gz[18] * zij) + Gz[23]);
        tile[539] += sc * (Gx[0]) * (Gy[0]) * (Gz[14] * zij2 + 2.0 * (Gz[19] * zij) + Gz[24]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(540);
